//! Hypothesis testing framework for statistical models
//!
//! This module provides various hypothesis tests including Wald tests,
//! likelihood ratio tests, and score tests.

use faer::{prelude::*, Mat};
use statrs::distribution::{ChiSquared, ContinuousCDF, FisherSnedecor};

/// Result of a hypothesis test
#[derive(Debug)]
pub struct TestResult {
    /// Test statistic value
    pub statistic: f64,
    /// Degrees of freedom
    pub df: usize,
    /// p-value
    pub p_value: f64,
    /// Test name/description
    pub test_name: String,
}

/// Wald test for linear hypotheses
///
/// Tests H0: R*beta = r where R is the constraint matrix
///
/// # Arguments
/// * `beta` - Parameter estimates
/// * `cov_beta` - Variance-covariance matrix of parameters
/// * `r_matrix` - Constraint matrix R (q × p)
/// * `r_values` - Constraint values r (q × 1), defaults to zero vector
pub fn wald_test(
    beta: &[f64],
    cov_beta: &Mat<f64>,
    r_matrix: &Mat<f64>,
    r_values: Option<&[f64]>,
) -> Result<TestResult, String> {
    let q = r_matrix.nrows(); // number of constraints
    let p = r_matrix.ncols(); // number of parameters

    if p != beta.len() {
        return Err("R matrix columns must match number of parameters".to_string());
    }

    if cov_beta.nrows() != p || cov_beta.ncols() != p {
        return Err("Covariance matrix dimensions must match number of parameters".to_string());
    }

    // Default r to zero vector
    let r_vec = r_values.unwrap_or(&vec![0.0; q]);
    if r_vec.len() != q {
        return Err("r vector length must match number of constraints".to_string());
    }

    // Compute R*beta - r
    let beta_mat = Mat::from_fn(p, 1, |i, _| beta[i]);
    let r_beta = r_matrix * &beta_mat;
    let diff = Mat::from_fn(q, 1, |i, _| r_beta[(i, 0)] - r_vec[i]);

    // Compute R * Cov(beta) * R'
    let r_cov = r_matrix * cov_beta;
    let r_cov_rt = &r_cov * r_matrix.transpose();

    // Invert R * Cov(beta) * R'
    let qr = r_cov_rt.col_piv_qr();
    let r_cov_rt_inv = qr.solve(&Mat::identity(q, q));

    // Compute Wald statistic: (R*beta - r)' * [R*Cov(beta)*R']^(-1) * (R*beta - r)
    let temp = &r_cov_rt_inv * &diff;
    let wald_stat = diff.transpose() * temp;
    let wald_value = wald_stat[(0, 0)];

    // Under H0, Wald statistic ~ Chi-squared(q)
    let chi2_dist = ChiSquared::new(q as f64).map_err(|e| e.to_string())?;
    let p_value = 1.0 - chi2_dist.cdf(wald_value);

    Ok(TestResult {
        statistic: wald_value,
        df: q,
        p_value,
        test_name: "Wald Test".to_string(),
    })
}

/// F-test for nested models
///
/// Tests whether the restricted model is adequate compared to the full model
///
/// # Arguments
/// * `rss_restricted` - Residual sum of squares for restricted model
/// * `rss_full` - Residual sum of squares for full model
/// * `df_restricted` - Degrees of freedom for restricted model
/// * `df_full` - Degrees of freedom for full model
pub fn f_test(
    rss_restricted: f64,
    rss_full: f64,
    df_restricted: usize,
    df_full: usize,
) -> Result<TestResult, String> {
    if df_restricted <= df_full {
        return Err("Restricted model must have more degrees of freedom than full model".to_string());
    }

    if rss_restricted < rss_full {
        return Err("Restricted model RSS cannot be less than full model RSS".to_string());
    }

    let df_diff = df_restricted - df_full;
    let f_stat = ((rss_restricted - rss_full) / df_diff as f64) / (rss_full / df_full as f64);

    let f_dist = FisherSnedecor::new(df_diff as f64, df_full as f64)
        .map_err(|e| e.to_string())?;
    let p_value = 1.0 - f_dist.cdf(f_stat);

    Ok(TestResult {
        statistic: f_stat,
        df: df_diff,
        p_value,
        test_name: "F-test".to_string(),
    })
}

/// Likelihood ratio test for nested models
///
/// Tests -2 * log(L_restricted / L_full) ~ Chi-squared(df_diff)
///
/// # Arguments
/// * `log_lik_restricted` - Log-likelihood of restricted model
/// * `log_lik_full` - Log-likelihood of full model
/// * `df_diff` - Difference in degrees of freedom between models
pub fn likelihood_ratio_test(
    log_lik_restricted: f64,
    log_lik_full: f64,
    df_diff: usize,
) -> Result<TestResult, String> {
    if log_lik_restricted > log_lik_full {
        return Err("Restricted model log-likelihood cannot exceed full model".to_string());
    }

    if df_diff == 0 {
        return Err("Models must differ in degrees of freedom".to_string());
    }

    let lr_stat = -2.0 * (log_lik_restricted - log_lik_full);

    let chi2_dist = ChiSquared::new(df_diff as f64).map_err(|e| e.to_string())?;
    let p_value = 1.0 - chi2_dist.cdf(lr_stat);

    Ok(TestResult {
        statistic: lr_stat,
        df: df_diff,
        p_value,
        test_name: "Likelihood Ratio Test".to_string(),
    })
}

/// Test a single coefficient against a specified value
///
/// # Arguments
/// * `coef` - Coefficient estimate
/// * `se` - Standard error of coefficient
/// * `null_value` - Value under null hypothesis (default 0)
pub fn single_coefficient_test(coef: f64, se: f64, null_value: Option<f64>) -> TestResult {
    let null = null_value.unwrap_or(0.0);
    let t_stat = (coef - null) / se;

    // For large samples, use normal approximation
    use statrs::distribution::{Normal, ContinuousCDF};
    let normal = Normal::new(0.0, 1.0).unwrap();
    let p_value = 2.0 * (1.0 - normal.cdf(t_stat.abs()));

    TestResult {
        statistic: t_stat,
        df: 1,
        p_value,
        test_name: format!("Test H0: coef = {}", null),
    }
}

/// Test linear combination of coefficients
///
/// Tests H0: c'*beta = value
pub fn linear_combination_test(
    beta: &[f64],
    cov_beta: &Mat<f64>,
    weights: &[f64],
    null_value: Option<f64>,
) -> Result<TestResult, String> {
    if beta.len() != weights.len() {
        return Err("Weights must match number of coefficients".to_string());
    }

    let null = null_value.unwrap_or(0.0);

    // Compute linear combination
    let combo: f64 = beta.iter().zip(weights).map(|(b, w)| b * w).sum();

    // Compute variance of linear combination: Var(c'*beta) = c' * Cov(beta) * c
    let mut var = 0.0;
    for i in 0..beta.len() {
        for j in 0..beta.len() {
            var += weights[i] * cov_beta[(i, j)] * weights[j];
        }
    }

    let se = var.sqrt();
    let z_stat = (combo - null) / se;

    use statrs::distribution::{Normal, ContinuousCDF};
    let normal = Normal::new(0.0, 1.0).unwrap();
    let p_value = 2.0 * (1.0 - normal.cdf(z_stat.abs()));

    Ok(TestResult {
        statistic: z_stat,
        df: 1,
        p_value,
        test_name: format!("Linear combination test: H0 = {}", null),
    })
}

#[cfg(test)]
mod tests {
    use super::*;
    use approx::assert_relative_eq;

    #[test]
    fn test_wald_single_constraint() {
        // Test H0: beta[1] = 0
        let beta = vec![1.0, 0.5];
        let cov_beta = Mat::from_fn(2, 2, |i, j| {
            if i == j { 0.1 } else { 0.01 }
        });

        // R = [0, 1] to test second coefficient
        let r_matrix = Mat::from_fn(1, 2, |_, j| if j == 1 { 1.0 } else { 0.0 });

        let result = wald_test(&beta, &cov_beta, &r_matrix, None).unwrap();

        assert_eq!(result.df, 1);
        assert!(result.statistic > 0.0);
        assert!(result.p_value >= 0.0 && result.p_value <= 1.0);
    }

    #[test]
    fn test_f_test() {
        let rss_restricted = 100.0;
        let rss_full = 80.0;
        let df_restricted = 10;
        let df_full = 8;

        let result = f_test(rss_restricted, rss_full, df_restricted, df_full).unwrap();

        assert_eq!(result.df, 2);
        assert!(result.statistic > 0.0);
        assert!(result.p_value >= 0.0 && result.p_value <= 1.0);
    }

    #[test]
    fn test_likelihood_ratio() {
        let log_lik_restricted = -100.0;
        let log_lik_full = -90.0;
        let df_diff = 2;

        let result = likelihood_ratio_test(log_lik_restricted, log_lik_full, df_diff).unwrap();

        assert_eq!(result.df, 2);
        assert_relative_eq!(result.statistic, 20.0, epsilon = 1e-10);
        assert!(result.p_value >= 0.0 && result.p_value <= 1.0);
    }
}

