                .map_err(|e| ModelError::LinearAlgebra(e.to_string()))?;

        let y_view = ndarray::ArrayView1::from(&self.y_vector);

        bootstrap(x_view, y_view, bootstrap_stat, Some(config))
            .map_err(|e| ModelError::LinearAlgebra(e.to_string()))
    }
