    let diagnostics = fit.diagnostics();

    // Generate R code to compute leverage
    let r_code = r#"
x <- matrix(c(1,1,1,1,1, 1,2,3,4,5), ncol=2)
y <- c(5.1, 7.9, 11.2, 13.8, 17.1)
model <- lm(y ~ x - 1)  # -1 because we already have intercept in x
h <- hatvalues(model)
cat(paste(h, collapse=","))
"#;

    let output = Command::new("Rscript")
        .arg("-e")
        .arg(r_code)
        .output()
        .expect("Failed to execute R");

    let r_leverage: Vec<f64> = String::from_utf8_lossy(&output.stdout)
        .trim()
        .split(',')
        .map(|s| s.parse().unwrap())
        .collect();

    // Compare leverage values
    for (i, (&rust_h, &r_h)) in diagnostics.leverage.iter().zip(r_leverage.iter()).enumerate() {
        assert_relative_eq!(rust_h, r_h, epsilon = 1e-10,
            "Leverage mismatch at observation {}: Rust={}, R={}", i, rust_h, r_h);
    }
}

/// Test Cook's distance against R
#[test]
fn test_cooks_distance() {
    // Test with some outliers
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0],
        [1.0, 6.0],
        [1.0, 10.0]  // Leverage point
    ];
    let y = array![2.1, 4.2, 6.1, 8.3, 10.2, 12.1, 25.0]; // Last point is influential

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();
    let diagnostics = fit.diagnostics();

    let r_code = r#"
x <- matrix(c(rep(1,7), 1,2,3,4,5,6,10), ncol=2)
y <- c(2.1, 4.2, 6.1, 8.3, 10.2, 12.1, 25.0)
model <- lm(y ~ x - 1)
cd <- cooks.distance(model)
cat(paste(cd, collapse=","))
"#;

    let output = Command::new("Rscript")
        .arg("-e")
        .arg(r_code)
        .output()
        .expect("Failed to execute R");

    let r_cooks: Vec<f64> = String::from_utf8_lossy(&output.stdout)
        .trim()
        .split(',')
        .map(|s| s.parse().unwrap())
        .collect();

    for (i, (&rust_cd, &r_cd)) in diagnostics.cooks_distance.iter().zip(r_cooks.iter()).enumerate() {
        assert_relative_eq!(rust_cd, r_cd, epsilon = 1e-10,
            "Cook's distance mismatch at observation {}: Rust={}, R={}", i, rust_cd, r_cd);
    }
}

/// Test confidence intervals against R
#[test]
fn test_confidence_intervals() {
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0],
        [1.0, 6.0]
    ];
    let y = array![2.5, 4.1, 6.3, 8.2, 10.1, 12.3];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();
    let ci = fit.confint(0.95).unwrap();

    let r_code = r#"
x <- matrix(c(rep(1,6), 1:6), ncol=2)
y <- c(2.5, 4.1, 6.3, 8.2, 10.1, 12.3)
model <- lm(y ~ x - 1)
ci <- confint(model, level=0.95)
cat(paste(ci[,1], collapse=","), ";", paste(ci[,2], collapse=","))
"#;

    let output = Command::new("Rscript")
        .arg("-e")
        .arg(r_code)
        .output()
        .expect("Failed to execute R");

    let output_str = String::from_utf8_lossy(&output.stdout);
    let parts: Vec<&str> = output_str.trim().split(';').collect();

    let r_lower: Vec<f64> = parts[0].trim().split(',')
        .map(|s| s.parse().unwrap())
        .collect();
    let r_upper: Vec<f64> = parts[1].trim().split(',')
        .map(|s| s.parse().unwrap())
        .collect();

    for i in 0..ci.len() {
        assert_relative_eq!(ci[i].lower, r_lower[i], epsilon = 1e-10,
            "CI lower bound mismatch for coefficient {}", i);
        assert_relative_eq!(ci[i].upper, r_upper[i], epsilon = 1e-10,
            "CI upper bound mismatch for coefficient {}", i);
    }
}

/// Test Wald test against R's car::linearHypothesis
#[test]
fn test_wald_test() {
    let x = array![
        [1.0, 1.0, 0.0],
        [1.0, 2.0, 0.0],
        [1.0, 3.0, 1.0],
        [1.0, 4.0, 1.0],
        [1.0, 5.0, 2.0],
        [1.0, 6.0, 2.0]
    ];
    let y = array![2.5, 4.1, 7.3, 9.2, 13.1, 15.3];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();

    // Test H0: beta[2] = 0 (third coefficient)
    let r_matrix = Mat::from_fn(1, 3, |_, j| if j == 2 { 1.0 } else { 0.0 });
    let test_result = fit.wald_test(&r_matrix, None).unwrap();

    let r_code = r#"
library(car)
x <- matrix(c(rep(1,6), 1:6, c(0,0,1,1,2,2)), ncol=3)
y <- c(2.5, 4.1, 7.3, 9.2, 13.1, 15.3)
model <- lm(y ~ x - 1)
test <- linearHypothesis(model, c("x3 = 0"))
cat(test$Chisq[2], ",", test$`Pr(>Chisq)`[2])
"#;

    let output = Command::new("Rscript")
        .arg("-e")
        .arg(r_code)
        .output()
        .expect("Failed to execute R");

    let output_str = String::from_utf8_lossy(&output.stdout);
    let parts: Vec<&str> = output_str.trim().split(',').collect();

    let r_statistic: f64 = parts[0].trim().parse().unwrap();
    let r_pvalue: f64 = parts[1].trim().parse().unwrap();

    assert_relative_eq!(test_result.statistic, r_statistic, epsilon = 1e-10,
        "Wald test statistic mismatch");
    assert_relative_eq!(test_result.p_value, r_pvalue, epsilon = 1e-10,
        "Wald test p-value mismatch");
}

/// Test prediction intervals against R
#[test]
fn test_prediction_intervals() {
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0]
    ];
    let y = array![2.5, 4.8, 7.1, 9.2, 11.5];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();

    // Predict for new data points
    let x_new = Mat::from_fn(2, 2, |i, j| {
        if j == 0 { 1.0 } else { (i + 6) as f64 }
    });

    let pred_intervals = fit.predict_interval(&x_new, 0.95).unwrap();

    let r_code = r#"
x <- matrix(c(rep(1,5), 1:5), ncol=2)
y <- c(2.5, 4.8, 7.1, 9.2, 11.5)
model <- lm(y ~ x - 1)
newdata <- data.frame(x1=1, x2=c(6,7))
colnames(newdata) <- c("x1", "x2")
pred <- predict(model, newdata, interval="prediction", level=0.95)
cat(paste(pred[,2], collapse=","), ";", paste(pred[,3], collapse=","))
"#;

    let output = Command::new("Rscript")
        .arg("-e")
        .arg(r_code)
        .output()
        .expect("Failed to execute R");

    let output_str = String::from_utf8_lossy(&output.stdout);
    let parts: Vec<&str> = output_str.trim().split(';').collect();

    let r_lower: Vec<f64> = parts[0].trim().split(',')
        .map(|s| s.parse().unwrap())
        .collect();
    let r_upper: Vec<f64> = parts[1].trim().split(',')
        .map(|s| s.parse().unwrap())
        .collect();

    for i in 0..pred_intervals.len() {
        assert_relative_eq!(pred_intervals[i].lower, r_lower[i], epsilon = 1e-9,
            "Prediction interval lower bound mismatch for observation {}", i);
        assert_relative_eq!(pred_intervals[i].upper, r_upper[i], epsilon = 1e-9,
            "Prediction interval upper bound mismatch for observation {}", i);
    }
}

/// Test VIF (Variance Inflation Factors) for multicollinearity
#[test]
fn test_vif() {
    // Create correlated predictors
    let x = array![
        [1.0, 1.0, 1.1],
        [1.0, 2.0, 2.2],
        [1.0, 3.0, 2.9],
        [1.0, 4.0, 4.1],
        [1.0, 5.0, 5.0],
        [1.0, 6.0, 5.8]
    ];
    let y = array![3.0, 5.5, 8.1, 10.2, 12.9, 15.1];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();
    let x_mat = Mat::from_fn(6, 3, |i, j| x[[i, j]]);
    let vif = diagnostics::compute_vif(&x_mat);

    let r_code = r#"
library(car)
x <- matrix(c(rep(1,6), 1:6, c(1.1,2.2,2.9,4.1,5.0,5.8)), ncol=3)
y <- c(3.0, 5.5, 8.1, 10.2, 12.9, 15.1)
model <- lm(y ~ x - 1)
# VIF not computed for intercept
vif_vals <- vif(model)[2:3]
cat(paste(vif_vals, collapse=","))
"#;

    let output = Command::new("Rscript")
        .arg("-e")
        .arg(r_code)
        .output()
        .expect("Failed to execute R");

    let r_vif: Vec<f64> = String::from_utf8_lossy(&output.stdout)
        .trim()
        .split(',')
        .map(|s| s.parse().unwrap())
        .collect();

    // Skip intercept (index 0) which has NaN VIF
    for i in 1..vif.len() {
        assert_relative_eq!(vif[i], r_vif[i-1], epsilon = 1e-9,
            "VIF mismatch for predictor {}: Rust={}, R={}", i, vif[i], r_vif[i-1]);
    }
}

