//! Confidence and prediction intervals for statistical models
//!
//! This module provides methods for computing confidence intervals
//! for parameters and prediction intervals for new observations.

use faer::{prelude::*, Mat};
use statrs::distribution::{ContinuousCDF, Normal, StudentsT};

/// Confidence interval for a parameter
#[derive(Debug, Clone)]
pub struct ConfidenceInterval {
    /// Point estimate
    pub estimate: f64,
    /// Lower bound
    pub lower: f64,
    /// Upper bound
    pub upper: f64,
    /// Confidence level (e.g., 0.95 for 95% CI)
    pub level: f64,
}

/// Prediction interval for a new observation
#[derive(Debug, Clone)]
pub struct PredictionInterval {
    /// Predicted value
    pub prediction: f64,
    /// Lower bound
    pub lower: f64,
    /// Upper bound
    pub upper: f64,
    /// Confidence level
    pub level: f64,
}

impl ConfidenceInterval {
    /// Check if a value is contained within the interval
    pub fn contains(&self, value: f64) -> bool {
        value >= self.lower && value <= self.upper
    }

    /// Width of the interval
    pub fn width(&self) -> f64 {
        self.upper - self.lower
    }
}

impl PredictionInterval {
    /// Check if a value is contained within the interval
    pub fn contains(&self, value: f64) -> bool {
        value >= self.lower && value <= self.upper
    }

    /// Width of the interval
    pub fn width(&self) -> f64 {
        self.upper - self.lower
    }
}

/// Compute confidence intervals for model parameters
///
/// # Arguments
/// * `estimates` - Parameter estimates
/// * `std_errors` - Standard errors of parameters
/// * `df` - Degrees of freedom (use None for normal approximation)
/// * `level` - Confidence level (e.g., 0.95 for 95% CI)
pub fn parameter_confidence_intervals(
    estimates: &[f64],
    std_errors: &[f64],
    df: Option<usize>,
    level: f64,
) -> Result<Vec<ConfidenceInterval>, String> {
    if estimates.len() != std_errors.len() {
        return Err("Estimates and standard errors must have same length".to_string());
    }

    if level <= 0.0 || level >= 1.0 {
        return Err("Confidence level must be between 0 and 1".to_string());
    }

    let alpha = 1.0 - level;
    let critical_value = match df {
        Some(degrees) if degrees > 0 => {
            // Use t-distribution
            let t_dist = StudentsT::new(0.0, 1.0, degrees as f64)
                .map_err(|e| e.to_string())?;
            t_dist.inverse_cdf(1.0 - alpha / 2.0)
        }
        _ => {
            // Use normal approximation
            let normal = Normal::new(0.0, 1.0).unwrap();
            normal.inverse_cdf(1.0 - alpha / 2.0)
        }
    };

    let intervals: Vec<ConfidenceInterval> = estimates.iter()
        .zip(std_errors)
        .map(|(&est, &se)| {
            let margin = critical_value * se;
            ConfidenceInterval {
                estimate: est,
                lower: est - margin,
                upper: est + margin,
                level,
            }
        })
        .collect();

    Ok(intervals)
}

/// Compute confidence interval for a linear combination of parameters
///
/// # Arguments
/// * `estimates` - Parameter estimates
/// * `cov_matrix` - Variance-covariance matrix
/// * `weights` - Linear combination weights
/// * `df` - Degrees of freedom
/// * `level` - Confidence level
pub fn linear_combination_confidence_interval(
    estimates: &[f64],
    cov_matrix: &Mat<f64>,
    weights: &[f64],
    df: Option<usize>,
    level: f64,
) -> Result<ConfidenceInterval, String> {
    if estimates.len() != weights.len() {
        return Err("Estimates and weights must have same length".to_string());
    }

    if cov_matrix.nrows() != estimates.len() || cov_matrix.ncols() != estimates.len() {
        return Err("Covariance matrix dimensions must match number of parameters".to_string());
    }

    // Compute point estimate
    let estimate: f64 = estimates.iter()
        .zip(weights)
        .map(|(e, w)| e * w)
        .sum();

    // Compute variance: w' * Cov * w
    let mut variance = 0.0;
    for i in 0..estimates.len() {
        for j in 0..estimates.len() {
            variance += weights[i] * cov_matrix[(i, j)] * weights[j];
        }
    }
    let std_error = variance.sqrt();

    // Get critical value
    let alpha = 1.0 - level;
    let critical_value = match df {
        Some(degrees) if degrees > 0 => {
            let t_dist = StudentsT::new(0.0, 1.0, degrees as f64)
                .map_err(|e| e.to_string())?;
            t_dist.inverse_cdf(1.0 - alpha / 2.0)
        }
        _ => {
            let normal = Normal::new(0.0, 1.0).unwrap();
            normal.inverse_cdf(1.0 - alpha / 2.0)
        }
    };

    let margin = critical_value * std_error;

    Ok(ConfidenceInterval {
        estimate,
        lower: estimate - margin,
        upper: estimate + margin,
        level,
    })
}

/// Compute prediction interval for new observations
///
/// # Arguments
/// * `x_new` - Design matrix for new observations (m × p)
/// * `beta` - Parameter estimates (p × 1)
/// * `cov_beta` - Variance-covariance matrix of parameters (p × p)
/// * `sigma` - Residual standard error
/// * `df` - Residual degrees of freedom
/// * `level` - Confidence level
pub fn prediction_intervals(
    x_new: &Mat<f64>,
    beta: &[f64],
    cov_beta: &Mat<f64>,
    sigma: f64,
    df: usize,
    level: f64,
) -> Result<Vec<PredictionInterval>, String> {
    let m = x_new.nrows(); // number of new observations
    let p = x_new.ncols(); // number of predictors

    if beta.len() != p {
        return Err("Beta length must match number of predictors".to_string());
    }

    if cov_beta.nrows() != p || cov_beta.ncols() != p {
        return Err("Covariance matrix dimensions must match number of parameters".to_string());
    }

    // Get critical value from t-distribution
    let alpha = 1.0 - level;
    let t_dist = StudentsT::new(0.0, 1.0, df as f64)
        .map_err(|e| e.to_string())?;
    let critical_value = t_dist.inverse_cdf(1.0 - alpha / 2.0);

    let mut intervals = Vec::with_capacity(m);

    for i in 0..m {
        // Compute prediction: x_new[i,] * beta
        let mut prediction = 0.0;
        for j in 0..p {
            prediction += x_new[(i, j)] * beta[j];
        }

        // Compute variance of prediction
        // Var(y_new) = sigma^2 + Var(x_new' * beta)
        // Var(x_new' * beta) = x_new' * Cov(beta) * x_new
        let mut var_mean = 0.0;
        for j in 0..p {
            for k in 0..p {
                var_mean += x_new[(i, j)] * cov_beta[(j, k)] * x_new[(i, k)];
            }
        }

        // Total prediction variance
        let var_pred = sigma * sigma + var_mean;
        let se_pred = var_pred.sqrt();

        let margin = critical_value * se_pred;

        intervals.push(PredictionInterval {
            prediction,
            lower: prediction - margin,
            upper: prediction + margin,
            level,
        });
    }

    Ok(intervals)
}

/// Simultaneous confidence bands using Working-Hotelling method
///
/// Provides confidence bands that cover the entire regression line
/// with the specified confidence level
pub fn working_hotelling_bands(
    x: &Mat<f64>,
    beta: &[f64],
    cov_beta: &Mat<f64>,
    sigma: f64,
    df: usize,
    level: f64,
) -> Result<Vec<ConfidenceInterval>, String> {
    let n = x.nrows();
    let p = x.ncols();

    // Working-Hotelling multiplier: sqrt(p * F_{p,n-p,1-alpha})
    use statrs::distribution::FisherSnedecor;
    let f_dist = FisherSnedecor::new(p as f64, df as f64)
        .map_err(|e| e.to_string())?;
    let f_critical = f_dist.inverse_cdf(level);
    let wh_multiplier = (p as f64 * f_critical).sqrt();

    let mut bands = Vec::with_capacity(n);

    for i in 0..n {
        // Compute fitted value
        let mut fitted = 0.0;
        for j in 0..p {
            fitted += x[(i, j)] * beta[j];
        }

        // Compute standard error of fitted value
        let mut var_fitted = 0.0;
        for j in 0..p {
            for k in 0..p {
                var_fitted += x[(i, j)] * cov_beta[(j, k)] * x[(i, k)];
            }
        }
        let se_fitted = var_fitted.sqrt();

        let margin = wh_multiplier * se_fitted;

        bands.push(ConfidenceInterval {
            estimate: fitted,
            lower: fitted - margin,
            upper: fitted + margin,
            level,
        });
    }

    Ok(bands)
}

#[cfg(test)]
mod tests {
    use super::*;
    use approx::assert_relative_eq;

    #[test]
    fn test_parameter_confidence_intervals() {
        let estimates = vec![1.0, 2.0, 3.0];
        let std_errors = vec![0.1, 0.2, 0.15];
        let df = Some(10);
        let level = 0.95;

        let intervals = parameter_confidence_intervals(&estimates, &std_errors, df, level).unwrap();

        assert_eq!(intervals.len(), 3);

        // Check that estimates are centered in intervals
        for (est, ci) in estimates.iter().zip(&intervals) {
            assert_relative_eq!(*est, ci.estimate, epsilon = 1e-10);
            assert!(ci.lower < *est);
            assert!(ci.upper > *est);
            assert_relative_eq!(ci.level, level, epsilon = 1e-10);
        }
    }

    #[test]
    fn test_interval_contains() {
        let ci = ConfidenceInterval {
            estimate: 2.0,
            lower: 1.0,
            upper: 3.0,
            level: 0.95,
        };

        assert!(ci.contains(2.0));
        assert!(ci.contains(1.5));
        assert!(!ci.contains(0.5));
        assert!(!ci.contains(3.5));

        assert_relative_eq!(ci.width(), 2.0, epsilon = 1e-10);
    }

    #[test]
    fn test_linear_combination_ci() {
        let estimates = vec![1.0, 2.0];
        let cov_matrix = Mat::from_fn(2, 2, |i, j| {
            if i == j { 0.1 } else { 0.01 }
        });
        let weights = vec![1.0, -1.0]; // Difference between parameters

        let ci = linear_combination_confidence_interval(
            &estimates,
            &cov_matrix,
            &weights,
            Some(10),
            0.95
        ).unwrap();

        assert_relative_eq!(ci.estimate, -1.0, epsilon = 1e-10); // 1.0 - 2.0
        assert!(ci.lower < ci.estimate);
        assert!(ci.upper > ci.estimate);
    }
}

