//! Integration tests for model diagnostics

use approx::assert_relative_eq;
use ndarray::array;
use stats_models::{Lm, diagnostics, hypothesis_tests, intervals};
use faer::Mat;

#[test]
fn test_diagnostics_basic() {
    // Simple regression: y = 2 + 3*x
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0]
    ];
    let y = array![5.0, 8.0, 11.0, 14.0, 17.0];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();
    let diag = fit.diagnostics();

    // Check that we get results for all observations
    assert_eq!(diag.leverage.len(), 5);
    assert_eq!(diag.cooks_distance.len(), 5);
    assert_eq!(diag.standardized_residuals.len(), 5);

    // Leverage should sum to number of parameters (p = 2)
    let leverage_sum: f64 = diag.leverage.iter().sum();
    assert_relative_eq!(leverage_sum, 2.0, epsilon = 1e-10);

    // All values should be finite
    for i in 0..5 {
        assert!(diag.leverage[i].is_finite());
        assert!(diag.cooks_distance[i].is_finite());
        assert!(diag.standardized_residuals[i].is_finite());
    }
}

#[test]
fn test_confidence_intervals() {
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0],
        [1.0, 6.0]
    ];
    let y = array![2.5, 4.1, 6.3, 8.2, 10.1, 12.3];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();
    let ci = fit.confint(0.95).unwrap();

    assert_eq!(ci.len(), 2); // Two parameters

    // Check that estimates are within confidence intervals
    for (i, interval) in ci.iter().enumerate() {
        assert!(interval.contains(fit.coefficients()[i]));
        assert!(interval.lower < interval.upper);
        assert_relative_eq!(interval.level, 0.95);
    }
}

#[test]
fn test_wald_test_single_coefficient() {
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0]
    ];
    let y = array![5.0, 8.0, 11.0, 14.0, 17.0];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();

    // Test H0: beta[1] = 0 (slope = 0)
    let r_matrix = Mat::from_fn(1, 2, |_, j| if j == 1 { 1.0 } else { 0.0 });
    let result = fit.wald_test(&r_matrix, None).unwrap();

    assert_eq!(result.df, 1);
    assert!(result.statistic > 0.0);
    assert!(result.p_value >= 0.0 && result.p_value <= 1.0);

    // For this perfect fit, p-value should be very small
    assert!(result.p_value < 0.001);
}

#[test]
fn test_prediction_intervals() {
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 5.0]
    ];
    let y = array![2.5, 4.8, 7.1, 9.2, 11.5];

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();

    // Predict for new points
    let x_new = Mat::from_fn(2, 2, |i, j| {
        if j == 0 { 1.0 } else { (i + 6) as f64 }
    });

    let pred = fit.predict_interval(&x_new, 0.95).unwrap();

    assert_eq!(pred.len(), 2);

    // Prediction intervals should be wider than confidence intervals
    for interval in &pred {
        assert!(interval.lower < interval.prediction);
        assert!(interval.upper > interval.prediction);
        assert_relative_eq!(interval.level, 0.95);
    }
}

#[test]
fn test_vif_multicollinearity() {
    // Create highly correlated predictors
    let x_mat = Mat::from_fn(10, 3, |i, j| {
        match j {
            0 => 1.0, // intercept
            1 => i as f64,
            2 => i as f64 + 0.1 * (i % 2) as f64, // highly correlated with column 1
            _ => unreachable!()
        }
    });

    let vif = diagnostics::compute_vif(&x_mat);

    assert_eq!(vif.len(), 3);
    assert!(vif[0].is_nan()); // Intercept VIF is NaN by convention

    // High correlation should lead to high VIF values
    assert!(vif[1] > 5.0); // Common threshold for multicollinearity
    assert!(vif[2] > 5.0);
}

#[test]
fn test_influential_observations() {
    // Create data with an outlier
    let x = array![
        [1.0, 1.0],
        [1.0, 2.0],
        [1.0, 3.0],
        [1.0, 4.0],
        [1.0, 10.0] // High leverage point
    ];
    let y = array![2.0, 4.0, 6.0, 8.0, 50.0]; // Last point is influential

    let fit = Lm::fit_ndarray(x.view(), y.view()).unwrap();
    let diag = fit.diagnostics();

    let influential = diagnostics::identify_influential(&diag, 5, 2);

    // The last observation should be identified as influential
    assert!(influential.contains(&4));
}

