     1→//! Model diagnostics and influence measures
     2→//!
     3→//! This module provides diagnostic tools for assessing model fit quality,
     4→//! including leverage, Cook's distance, and standardized residuals.
     5→
     6→use faer::{prelude::*, Mat};
     7→
     8→/// Model diagnostics container
     9→#[derive(Debug)]
    10→pub struct ModelDiagnostics {
    11→    /// Standardized residuals
    12→    pub standardized_residuals: Vec<f64>,
    13→    /// Studentized residuals (leave-one-out residuals)
    14→    pub studentized_residuals: Vec<f64>,
    15→    /// Leverage values (diagonal of hat matrix)
    16→    pub leverage: Vec<f64>,
    17→    /// Cook's distance for each observation
    18→    pub cooks_distance: Vec<f64>,
    19→    /// DFFITS values
    20→    pub dffits: Vec<f64>,
    21→}
    22→
    23→/// Compute comprehensive model diagnostics
    24→///
    25→/// # Arguments
    26→/// * `x` - Design matrix (n × p)
    27→/// * `residuals` - Raw residuals
    28→/// * `sigma` - Residual standard error
    29→pub fn compute_diagnostics(x: &Mat<f64>, residuals: &[f64], sigma: f64) -> ModelDiagnostics {
    30→    let n = x.nrows();
    31→    let p = x.ncols();
    32→    
    33→    // Compute hat matrix diagonal elements (leverage)
    34→    // H = X(X'X)^(-1)X'
    35→    // We only need diagonal elements: h_ii = x_i'(X'X)^(-1)x_i
    36→    let xtx = x.transpose() * x;
    37→    let qr = xtx.col_piv_qr();
    38→    let identity = Mat::identity(xtx.nrows(), xtx.ncols());
    39→    let xtx_inv = qr.solve(&identity);
    40→    
    41→    let mut leverage = vec![0.0; n];
    42→    for i in 0..n {
    43→        let xi = x.row(i);
    44→        // h_ii = x_i' * (X'X)^(-1) * x_i
    45→        let mut h_ii = 0.0;
    46→        for j in 0..p {
    47→            for k in 0..p {
    48→                h_ii += xi[j] * xtx_inv[(j, k)] * xi[k];
    49→            }
    50→        }
    51→        leverage[i] = h_ii;
    52→    }
    53→    
    54→    // Compute standardized residuals: e_i / (sigma * sqrt(1 - h_ii))
    55→    let standardized_residuals: Vec<f64> = residuals.iter()
    56→        .zip(&leverage)
    57→        .map(|(&r, &h)| r / (sigma * (1.0 - h).sqrt()))
    58→        .collect();
    59→    
    60→    // Compute studentized residuals (externally studentized)
    61→    // These use leave-one-out variance estimates
    62→    let mut studentized_residuals = vec![0.0; n];
    63→    let df = (n - p) as f64;
    64→    
    65→    for i in 0..n {
    66→        let h_i = leverage[i];
    67→        let e_i = residuals[i];
    68→        
    69→        // Leave-one-out variance estimate
    70→        let rss_without_i = residuals.iter()
    71→            .enumerate()
    72→            .filter(|(j, _)| *j != i)
    73→            .map(|(_, r)| r * r)
    74→            .sum::<f64>();
    75→        
    76→        let sigma_without_i = (rss_without_i / (df - 1.0)).sqrt();
    77→        studentized_residuals[i] = e_i / (sigma_without_i * (1.0 - h_i).sqrt());
    78→    }
    79→    
    80→    // Compute Cook's distance
    81→    // D_i = (e_i^2 / (p * sigma^2)) * (h_ii / (1 - h_ii)^2)
    82→    let cooks_distance: Vec<f64> = residuals.iter()
    83→        .zip(&leverage)
    84→        .map(|(&r, &h)| {
    85→            let std_resid = r / (sigma * (1.0 - h).sqrt());
    86→            (std_resid * std_resid / p as f64) * (h / (1.0 - h))
    87→        })
    88→        .collect();
    89→    
    90→    // Compute DFFITS
    91→    // DFFITS_i = studentized_residual_i * sqrt(h_ii / (1 - h_ii))
    92→    let dffits: Vec<f64> = studentized_residuals.iter()
    93→        .zip(&leverage)
    94→        .map(|(&sr, &h)| sr * (h / (1.0 - h)).sqrt())
    95→        .collect();
    96→    
    97→    ModelDiagnostics {
    98→        standardized_residuals,
    99→        studentized_residuals,
   100→        leverage,
   101→        cooks_distance,
   102→        dffits,
   103→    }
   104→}
   105→
   106→/// Identify influential observations based on common thresholds
   107→pub fn identify_influential(diagnostics: &ModelDiagnostics, n: usize, p: usize) -> Vec<usize> {
   108→    let mut influential = Vec::new();
   109→    
   110→    // Common thresholds:
   111→    // - Leverage > 2p/n or > 3p/n
   112→    // - Cook's D > 4/(n-p) or > 1
   113→    // - |DFFITS| > 2*sqrt(p/n)
   114→    
   115→    let leverage_threshold = 2.0 * p as f64 / n as f64;
   116→    let cooks_threshold = 4.0 / (n - p) as f64;
   117→    let dffits_threshold = 2.0 * (p as f64 / n as f64).sqrt();
   118→    
   119→    for i in 0..n {
   120→        if diagnostics.leverage[i] > leverage_threshold
   121→            || diagnostics.cooks_distance[i] > cooks_threshold
   122→            || diagnostics.dffits[i].abs() > dffits_threshold
   123→        {
   124→            influential.push(i);
   125→        }
   126→    }
   127→    
   128→    influential
   129→}
   130→
   131→/// Variance Inflation Factor (VIF) for multicollinearity detection
   132→pub fn compute_vif(x: &Mat<f64>) -> Vec<f64> {
   133→    let p = x.ncols();
   134→    let mut vif = vec![0.0; p];
   135→    
   136→    // For each predictor, regress it on all other predictors
   137→    // VIF_j = 1 / (1 - R_j^2)
   138→    for j in 0..p {
   139→        if j == 0 {
   140→            // Skip intercept if present (assuming first column is intercept)
   141→            vif[j] = f64::NAN;
   142→            continue;
   143→        }
   144→        
   145→        // Create design matrix without column j
   146→        let mut x_without_j = Mat::zeros(x.nrows(), p - 1);
   147→        let mut col_idx = 0;
   148→        for k in 0..p {
   149→            if k != j {
   150→                for i in 0..x.nrows() {
   151→                    x_without_j[(i, col_idx)] = x[(i, k)];
   152→                }
   153→                col_idx += 1;
   154→            }
   155→        }
   156→        
   157→        // Response is column j
   158→        let y_j: Vec<f64> = (0..x.nrows()).map(|i| x[(i, j)]).collect();
   159→        
   160→        // Fit model: X_j ~ X_{-j}
   161→        let xtx = x_without_j.transpose() * &x_without_j;
   162→        let xty: Mat<f64> = x_without_j.transpose() * Mat::from_fn(x.nrows(), 1, |i, _| y_j[i]);
   163→        
   164→        let qr = xtx.col_piv_qr();
   165→        let beta = qr.solve(&xty);
   166→        
   167→        // Calculate R-squared
   168→        let y_mean = y_j.iter().sum::<f64>() / y_j.len() as f64;
   169→        let mut tss = 0.0;
   170→        let mut rss = 0.0;
   171→        
   172→        for i in 0..x.nrows() {
   173→            let fitted = (0..x_without_j.ncols())
   174→                .map(|k| x_without_j[(i, k)] * beta[(k, 0)])
   175→                .sum::<f64>();
   176→            let residual = y_j[i] - fitted;
   177→            rss += residual * residual;
   178→            tss += (y_j[i] - y_mean).powi(2);
   179→        }
   180→        
   181→        let r_squared = 1.0 - rss / tss;
