//! Model diagnostics and influence measures
//!
//! This module provides diagnostic tools for assessing model fit quality,
//! including leverage, Cook's distance, and standardized residuals.

use faer::{prelude::*, Mat};

/// Model diagnostics container
#[derive(Debug)]
pub struct ModelDiagnostics {
    /// Standardized residuals
    pub standardized_residuals: Vec<f64>,
    /// Studentized residuals (leave-one-out residuals)
    pub studentized_residuals: Vec<f64>,
    /// Leverage values (diagonal of hat matrix)
    pub leverage: Vec<f64>,
    /// Cook's distance for each observation
    pub cooks_distance: Vec<f64>,
    /// DFFITS values
    pub dffits: Vec<f64>,
}

/// Compute comprehensive model diagnostics
///
/// # Arguments
/// * `x` - Design matrix (n × p)
/// * `residuals` - Raw residuals
/// * `sigma` - Residual standard error
pub fn compute_diagnostics(x: &Mat<f64>, residuals: &[f64], sigma: f64) -> ModelDiagnostics {
    let n = x.nrows();
    let p = x.ncols();

    // Compute hat matrix diagonal elements (leverage)
    // H = X(X'X)^(-1)X'
    // We only need diagonal elements: h_ii = x_i'(X'X)^(-1)x_i
    let xtx = x.transpose() * x;
    let qr = xtx.col_piv_qr();
    let identity = Mat::identity(xtx.nrows(), xtx.ncols());
    let xtx_inv = qr.solve(&identity);

    let mut leverage = vec![0.0; n];
    for i in 0..n {
        let xi = x.row(i);
        // h_ii = x_i' * (X'X)^(-1) * x_i
        let mut h_ii = 0.0;
        for j in 0..p {
            for k in 0..p {
                h_ii += xi[j] * xtx_inv[(j, k)] * xi[k];
            }
        }
        leverage[i] = h_ii;
    }

    // Compute standardized residuals: e_i / (sigma * sqrt(1 - h_ii))
    let standardized_residuals: Vec<f64> = residuals.iter()
        .zip(&leverage)
        .map(|(&r, &h)| r / (sigma * (1.0 - h).sqrt()))
        .collect();

    // Compute studentized residuals (externally studentized)
    // These use leave-one-out variance estimates
    let mut studentized_residuals = vec![0.0; n];
    let df = (n - p) as f64;

    for i in 0..n {
        let h_i = leverage[i];
        let e_i = residuals[i];

        // Leave-one-out variance estimate
        let rss_without_i = residuals.iter()
            .enumerate()
            .filter(|(j, _)| *j != i)
            .map(|(_, r)| r * r)
            .sum::<f64>();

        let sigma_without_i = (rss_without_i / (df - 1.0)).sqrt();
        studentized_residuals[i] = e_i / (sigma_without_i * (1.0 - h_i).sqrt());
    }

    // Compute Cook's distance
    // D_i = (e_i^2 / (p * sigma^2)) * (h_ii / (1 - h_ii)^2)
    let cooks_distance: Vec<f64> = residuals.iter()
        .zip(&leverage)
        .map(|(&r, &h)| {
            let std_resid = r / (sigma * (1.0 - h).sqrt());
            (std_resid * std_resid / p as f64) * (h / (1.0 - h))
        })
        .collect();

    // Compute DFFITS
    // DFFITS_i = studentized_residual_i * sqrt(h_ii / (1 - h_ii))
    let dffits: Vec<f64> = studentized_residuals.iter()
        .zip(&leverage)
        .map(|(&sr, &h)| sr * (h / (1.0 - h)).sqrt())
        .collect();

    ModelDiagnostics {
        standardized_residuals,
        studentized_residuals,
        leverage,
        cooks_distance,
        dffits,
    }
}

/// Identify influential observations based on common thresholds
pub fn identify_influential(diagnostics: &ModelDiagnostics, n: usize, p: usize) -> Vec<usize> {
    let mut influential = Vec::new();

    // Common thresholds:
    // - Leverage > 2p/n or > 3p/n
    // - Cook's D > 4/(n-p) or > 1
    // - |DFFITS| > 2*sqrt(p/n)

    let leverage_threshold = 2.0 * p as f64 / n as f64;
    let cooks_threshold = 4.0 / (n - p) as f64;
    let dffits_threshold = 2.0 * (p as f64 / n as f64).sqrt();

    for i in 0..n {
        if diagnostics.leverage[i] > leverage_threshold
            || diagnostics.cooks_distance[i] > cooks_threshold
            || diagnostics.dffits[i].abs() > dffits_threshold
        {
            influential.push(i);
        }
    }

    influential
}

/// Variance Inflation Factor (VIF) for multicollinearity detection
pub fn compute_vif(x: &Mat<f64>) -> Vec<f64> {
    let p = x.ncols();
    let mut vif = vec![0.0; p];

    // For each predictor, regress it on all other predictors
    // VIF_j = 1 / (1 - R_j^2)
    for j in 0..p {
        if j == 0 {
            // Skip intercept if present (assuming first column is intercept)
            vif[j] = f64::NAN;
            continue;
        }

        // Create design matrix without column j
        let mut x_without_j = Mat::zeros(x.nrows(), p - 1);
        let mut col_idx = 0;
        for k in 0..p {
            if k != j {
                for i in 0..x.nrows() {
                    x_without_j[(i, col_idx)] = x[(i, k)];
                }
                col_idx += 1;
            }
        }

        // Response is column j
        let y_j: Vec<f64> = (0..x.nrows()).map(|i| x[(i, j)]).collect();

        // Fit model: X_j ~ X_{-j}
        let xtx = x_without_j.transpose() * &x_without_j;
        let xty: Mat<f64> = x_without_j.transpose() * Mat::from_fn(x.nrows(), 1, |i, _| y_j[i]);

        let qr = xtx.col_piv_qr();
        let beta = qr.solve(&xty);

        // Calculate R-squared
        let y_mean = y_j.iter().sum::<f64>() / y_j.len() as f64;
        let mut tss = 0.0;
        let mut rss = 0.0;

        for i in 0..x.nrows() {
            let fitted = (0..x_without_j.ncols())
                .map(|k| x_without_j[(i, k)] * beta[(k, 0)])
                .sum::<f64>();
            let residual = y_j[i] - fitted;
            rss += residual * residual;
            tss += (y_j[i] - y_mean).powi(2);
        }

        let r_squared = 1.0 - rss / tss;
        vif[j] = 1.0 / (1.0 - r_squared);
    }

    vif
}

#[cfg(test)]
mod tests {
    use super::*;
    use approx::assert_relative_eq;

    #[test]
    fn test_leverage_simple() {
        // Simple 2x2 design matrix
        let x = Mat::from_fn(3, 2, |i, j| {
            if j == 0 { 1.0 } // intercept
            else { (i + 1) as f64 } // predictor: 1, 2, 3
        });

        let residuals = vec![0.1, -0.2, 0.1];
        let sigma = 0.5;

        let diag = compute_diagnostics(&x, &residuals, sigma);

        // Leverage values should sum to p (number of parameters)
        let leverage_sum: f64 = diag.leverage.iter().sum();
        assert_relative_eq!(leverage_sum, 2.0, epsilon = 1e-10);

        // All leverage values should be between 0 and 1
        for &h in &diag.leverage {
            assert!(h >= 0.0 && h <= 1.0);
        }
    }

    #[test]
    fn test_cooks_distance() {
        let x = Mat::from_fn(5, 2, |i, j| {
            if j == 0 { 1.0 }
            else { (i + 1) as f64 }
        });

        let residuals = vec![0.1, -0.1, 0.2, -0.15, 0.05];
        let sigma = 0.2;

        let diag = compute_diagnostics(&x, &residuals, sigma);

        // Cook's distance should be non-negative
        for &d in &diag.cooks_distance {
            assert!(d >= 0.0);
        }
    }
}

