     6→use faer::{prelude::*, Mat};
     7→use statrs::distribution::{ChiSquared, ContinuousCDF, FisherSnedecor};
     8→
     9→/// Result of a hypothesis test
    10→#[derive(Debug)]
    11→pub struct TestResult {
    12→    /// Test statistic value
    13→    pub statistic: f64,
    14→    /// Degrees of freedom
    15→    pub df: usize,
    16→    /// p-value
    17→    pub p_value: f64,
    18→    /// Test name/description
    19→    pub test_name: String,
    20→}
    21→
    22→/// Wald test for linear hypotheses
    23→///
    24→/// Tests H0: R*beta = r where R is the constraint matrix
    25→///
    26→/// # Arguments
    27→/// * `beta` - Parameter estimates
    28→/// * `cov_beta` - Variance-covariance matrix of parameters
    29→/// * `r_matrix` - Constraint matrix R (q × p)
    30→/// * `r_values` - Constraint values r (q × 1), defaults to zero vector
    31→pub fn wald_test(
    32→    beta: &[f64],
    33→    cov_beta: &Mat<f64>,
    34→    r_matrix: &Mat<f64>,
    35→    r_values: Option<&[f64]>,
    36→) -> Result<TestResult, String> {
    37→    let q = r_matrix.nrows(); // number of constraints
    38→    let p = r_matrix.ncols(); // number of parameters
    39→    
    40→    if p != beta.len() {
    41→        return Err("R matrix columns must match number of parameters".to_string());
    42→    }
    43→    
    44→    if cov_beta.nrows() != p || cov_beta.ncols() != p {
    45→        return Err("Covariance matrix dimensions must match number of parameters".to_string());
    46→    }
    47→    
    48→    // Default r to zero vector
    49→    let zero_vec = vec![0.0; q];
    50→    let r_vec = r_values.unwrap_or(&zero_vec);
    51→    if r_vec.len() != q {
    52→        return Err("r vector length must match number of constraints".to_string());
    53→    }
    54→    
    55→    // Compute R*beta - r
    56→    let beta_mat = Mat::from_fn(p, 1, |i, _| beta[i]);
    57→    let r_beta = r_matrix * &beta_mat;
    58→    let diff = Mat::from_fn(q, 1, |i, _| r_beta[(i, 0)] - r_vec[i]);
    59→    
    60→    // Compute R * Cov(beta) * R'
    61→    let r_cov = r_matrix * cov_beta;
    62→    let r_cov_rt = &r_cov * r_matrix.transpose();
    63→    
    64→    // Invert R * Cov(beta) * R'
    65→    let qr = r_cov_rt.col_piv_qr();
    66→    let r_cov_rt_inv = qr.solve(&Mat::identity(q, q));
    67→    
    68→    // Compute Wald statistic: (R*beta - r)' * [R*Cov(beta)*R']^(-1) * (R*beta - r)
    69→    let temp = &r_cov_rt_inv * &diff;
    70→    let wald_stat = diff.transpose() * temp;
    71→    let wald_value = wald_stat[(0, 0)];
    72→    
    73→    // Under H0, Wald statistic ~ Chi-squared(q)
    74→    let chi2_dist = ChiSquared::new(q as f64).map_err(|e| e.to_string())?;
    75→    let p_value = 1.0 - chi2_dist.cdf(wald_value);
    76→    
    77→    Ok(TestResult {
    78→        statistic: wald_value,
    79→        df: q,
    80→        p_value,
    81→        test_name: "Wald Test".to_string(),
    82→    })
    83→}
    84→
    85→/// F-test for nested models
    86→///
    87→/// Tests whether the restricted model is adequate compared to the full model
    88→///
    89→/// # Arguments
    90→/// * `rss_restricted` - Residual sum of squares for restricted model
    91→/// * `rss_full` - Residual sum of squares for full model
    92→/// * `df_restricted` - Degrees of freedom for restricted model
    93→/// * `df_full` - Degrees of freedom for full model
    94→pub fn f_test(
    95→    rss_restricted: f64,
    96→    rss_full: f64,
    97→    df_restricted: usize,
    98→    df_full: usize,
    99→) -> Result<TestResult, String> {
   100→    if df_restricted <= df_full {
   101→        return Err("Restricted model must have more degrees of freedom than full model".to_string());
   102→    }
   103→    
   104→    if rss_restricted < rss_full {
   105→        return Err("Restricted model RSS cannot be less than full model RSS".to_string());
   106→    }
   107→    
   108→    let df_diff = df_restricted - df_full;
   109→    let f_stat = ((rss_restricted - rss_full) / df_diff as f64) / (rss_full / df_full as f64);
   110→    
   111→    let f_dist = FisherSnedecor::new(df_diff as f64, df_full as f64)
   112→        .map_err(|e| e.to_string())?;
   113→    let p_value = 1.0 - f_dist.cdf(f_stat);
   114→    
   115→    Ok(TestResult {
   116→        statistic: f_stat,
   117→        df: df_diff,
   118→        p_value,
   119→        test_name: "F-test".to_string(),
   120→    })
   121→}
   122→
   123→/// Likelihood ratio test for nested models
   124→///
   125→/// Tests -2 * log(L_restricted / L_full) ~ Chi-squared(df_diff)
   126→///
   127→/// # Arguments
   128→/// * `log_lik_restricted` - Log-likelihood of restricted model
   129→/// * `log_lik_full` - Log-likelihood of full model
   130→/// * `df_diff` - Difference in degrees of freedom between models
   131→pub fn likelihood_ratio_test(
   132→    log_lik_restricted: f64,
   133→    log_lik_full: f64,
   134→    df_diff: usize,
   135→) -> Result<TestResult, String> {
   136→    if log_lik_restricted > log_lik_full {
   137→        return Err("Restricted model log-likelihood cannot exceed full model".to_string());
   138→    }
   139→    
   140→    if df_diff == 0 {
   141→        return Err("Models must differ in degrees of freedom".to_string());
   142→    }
   143→    
   144→    let lr_stat = -2.0 * (log_lik_restricted - log_lik_full);
   145→    
   146→    let chi2_dist = ChiSquared::new(df_diff as f64).map_err(|e| e.to_string())?;
   147→    let p_value = 1.0 - chi2_dist.cdf(lr_stat);
   148→    
   149→    Ok(TestResult {
   150→        statistic: lr_stat,
   151→        df: df_diff,
   152→        p_value,
   153→        test_name: "Likelihood Ratio Test".to_string(),
   154→    })
   155→}
   156→
   157→/// Test a single coefficient against a specified value
   158→///
   159→/// # Arguments
   160→/// * `coef` - Coefficient estimate
   161→/// * `se` - Standard error of coefficient
   162→/// * `null_value` - Value under null hypothesis (default 0)
   163→pub fn single_coefficient_test(coef: f64, se: f64, null_value: Option<f64>) -> TestResult {
   164→    let null = null_value.unwrap_or(0.0);
   165→    let t_stat = (coef - null) / se;
   166→    
   167→    // For large samples, use normal approximation
   168→    use statrs::distribution::{Normal, ContinuousCDF};
   169→    let normal = Normal::new(0.0, 1.0).unwrap();
   170→    let p_value = 2.0 * (1.0 - normal.cdf(t_stat.abs()));
   171→    
   172→    TestResult {
   173→        statistic: t_stat,
   174→        df: 1,
   175→        p_value,
   176→        test_name: format!("Test H0: coef = {}", null),
   177→    }
   178→}
   179→
   180→/// Test linear combination of coefficients
   181→///
   182→/// Tests H0: c'*beta = value
   183→pub fn linear_combination_test(
   184→    beta: &[f64],
   185→    cov_beta: &Mat<f64>,
   186→    weights: &[f64],
   187→    null_value: Option<f64>,
   188→) -> Result<TestResult, String> {
   189→    if beta.len() != weights.len() {
   190→        return Err("Weights must match number of coefficients".to_string());
   191→    }
   192→    
   193→    let null = null_value.unwrap_or(0.0);
   194→    
   195→    // Compute linear combination
   196→    let combo: f64 = beta.iter().zip(weights).map(|(b, w)| b * w).sum();
   197→    
   198→    // Compute variance of linear combination: Var(c'*beta) = c' * Cov(beta) * c
   199→    let mut var = 0.0;
   200→    for i in 0..beta.len() {
   201→        for j in 0..beta.len() {
   202→            var += weights[i] * cov_beta[(i, j)] * weights[j];
   203→        }
   204→    }
   205→    
   206→    let se = var.sqrt();
   207→    let z_stat = (combo - null) / se;
   208→    
   209→    use statrs::distribution::{Normal, ContinuousCDF};
   210→    let normal = Normal::new(0.0, 1.0).unwrap();
   211→    let p_value = 2.0 * (1.0 - normal.cdf(z_stat.abs()));
   212→    
   213→    Ok(TestResult {
   214→        statistic: z_stat,
   215→        df: 1,
   216→        p_value,
   217→        test_name: format!("Linear combination test: H0 = {}", null),
   218→    })
   219→}
   220→
   221→#[cfg(test)]
   222→mod tests {
   223→    use super::*;
   224→    use approx::assert_relative_eq;
   225→    
   226→    #[test]
   227→    fn test_wald_single_constraint() {
   228→        // Test H0: beta[1] = 0
   229→        let beta = vec![1.0, 0.5];
   230→        let cov_beta = Mat::from_fn(2, 2, |i, j| {
   231→            if i == j { 0.1 } else { 0.01 }
   232→        });
   233→        
   234→        // R = [0, 1] to test second coefficient
   235→        let r_matrix = Mat::from_fn(1, 2, |_, j| if j == 1 { 1.0 } else { 0.0 });
   236→        
   237→        let result = wald_test(&beta, &cov_beta, &r_matrix, None).unwrap();
   238→        
   239→        assert_eq!(result.df, 1);
   240→        assert!(result.statistic > 0.0);
   241→        assert!(result.p_value >= 0.0 && result.p_value <= 1.0);
   242→    }
   243→    
   244→    #[test]
   245→    fn test_f_test() {
   246→        let rss_restricted = 100.0;
   247→        let rss_full = 80.0;
   248→        let df_restricted = 10;
   249→        let df_full = 8;
   250→        
   251→        let result = f_test(rss_restricted, rss_full, df_restricted, df_full).unwrap();
   252→        
   253→        assert_eq!(result.df, 2);
   254→        assert!(result.statistic > 0.0);
   255→        assert!(result.p_value >= 0.0 && result.p_value <= 1.0);
   256→    }
   257→    
   258→    #[test]
   259→    fn test_likelihood_ratio() {
   260→        let log_lik_restricted = -100.0;
   261→        let log_lik_full = -90.0;
   262→        let df_diff = 2;
   263→        
   264→        let result = likelihood_ratio_test(log_lik_restricted, log_lik_full, df_diff).unwrap();
   265→        
   266→        assert_eq!(result.df, 2);
   267→        assert_relative_eq!(result.statistic, 20.0, epsilon = 1e-10);
   268→        assert!(result.p_value >= 0.0 && result.p_value <= 1.0);
   269→    }
   270→}

