    59→/// Compute confidence intervals for model parameters
    60→///
    61→/// # Arguments
    62→/// * `estimates` - Parameter estimates
    63→/// * `std_errors` - Standard errors of parameters
    64→/// * `df` - Degrees of freedom (use None for normal approximation)
    65→/// * `level` - Confidence level (e.g., 0.95 for 95% CI)
    66→pub fn parameter_confidence_intervals(
    67→    estimates: &[f64],
    68→    std_errors: &[f64],
    69→    df: Option<usize>,
    70→    level: f64,
    71→) -> Result<Vec<ConfidenceInterval>, String> {
