   111→/// Compute confidence interval for a linear combination of parameters
   112→///
   113→/// # Arguments
   114→/// * `estimates` - Parameter estimates
   115→/// * `cov_matrix` - Variance-covariance matrix
   116→/// * `weights` - Linear combination weights
   117→/// * `df` - Degrees of freedom
   118→/// * `level` - Confidence level
   119→pub fn linear_combination_confidence_interval(
   120→    estimates: &[f64],
   121→    cov_matrix: &Mat<f64>,
   122→    weights: &[f64],
   123→    df: Option<usize>,
   124→    level: f64,
   125→) -> Result<ConfidenceInterval, String> {
   126→    if estimates.len() != weights.len() {
   127→        return Err("Estimates and weights must have same length".to_string());
   128→    }
   129→    
   130→    if cov_matrix.nrows() != estimates.len() || cov_matrix.ncols() != estimates.len() {
   131→        return Err("Covariance matrix dimensions must match number of parameters".to_string());
   132→    }
