   129→/// * `log_lik_full` - Log-likelihood of full model
   130→/// * `df_diff` - Difference in degrees of freedom between models
   131→pub fn likelihood_ratio_test(
   132→    log_lik_restricted: f64,
   133→    log_lik_full: f64,
   134→    df_diff: usize,
   135→) -> Result<TestResult, String> {
