   143→        for j in 0..estimates.len() {
   144→            variance += weights[i] * cov_matrix[(i, j)] * weights[j];
   145→        }
   146→    }
   147→    let std_error = variance.sqrt();
   148→    
   149→    // Get critical value
   150→    let alpha = 1.0 - level;
   151→    let critical_value = match df {
   152→        Some(degrees) if degrees > 0 => {
   153→            let t_dist = StudentsT::new(0.0, 1.0, degrees as f64)
   154→                .map_err(|e| e.to_string())?;
   155→            t_dist.inverse_cdf(1.0 - alpha / 2.0)
   156→        }
   157→        _ => {
   158→            let normal = Normal::new(0.0, 1.0).unwrap();
