   166→        estimate,
   167→        lower: estimate - margin,
   168→        upper: estimate + margin,
   169→        level,
   170→    })
   171→}
   172→
   173→/// Compute prediction interval for new observations
   174→///
   175→/// # Arguments
   176→/// * `x_new` - Design matrix for new observations (m × p)
   177→/// * `beta` - Parameter estimates (p × 1)
   178→/// * `cov_beta` - Variance-covariance matrix of parameters (p × p)
   179→/// * `sigma` - Residual standard error
   180→/// * `df` - Residual degrees of freedom
   181→/// * `level` - Confidence level
   182→pub fn prediction_intervals(
   183→    x_new: &Mat<f64>,
   184→    beta: &[f64],
   185→    cov_beta: &Mat<f64>,
   186→    sigma: f64,
   187→    df: usize,
   188→    level: f64,
   189→) -> Result<Vec<PredictionInterval>, String> {
   190→    let m = x_new.nrows(); // number of new observations
   191→    let p = x_new.ncols(); // number of predictors
   192→    
   193→    if beta.len() != p {
   194→        return Err("Beta length must match number of predictors".to_string());
   195→    }
   196→    
   197→    if cov_beta.nrows() != p || cov_beta.ncols() != p {
   198→        return Err("Covariance matrix dimensions must match number of parameters".to_string());
   199→    }
   200→    
   201→    // Get critical value from t-distribution
   202→    let alpha = 1.0 - level;
   203→    let t_dist = StudentsT::new(0.0, 1.0, df as f64)
   204→        .map_err(|e| e.to_string())?;
   205→    let critical_value = t_dist.inverse_cdf(1.0 - alpha / 2.0);
   206→    
   207→    let mut intervals = Vec::with_capacity(m);
   208→    
   209→    for i in 0..m {
   210→        // Compute prediction: x_new[i,] * beta
   211→        let mut prediction = 0.0;
   212→        for j in 0..p {
   213→            prediction += x_new[(i, j)] * beta[j];
   214→        }
   215→        
   216→        // Compute variance of prediction
   217→        // Var(y_new) = sigma^2 + Var(x_new' * beta)
   218→        // Var(x_new' * beta) = x_new' * Cov(beta) * x_new
   219→        let mut var_mean = 0.0;
   220→        for j in 0..p {
   221→            for k in 0..p {
   222→                var_mean += x_new[(i, j)] * cov_beta[(j, k)] * x_new[(i, k)];
   223→            }
   224→        }
   225→        
   226→        // Total prediction variance
   227→        let var_pred = sigma * sigma + var_mean;
   228→        let se_pred = var_pred.sqrt();
   229→        
   230→        let margin = critical_value * se_pred;
   231→        
   232→        intervals.push(PredictionInterval {
   233→            prediction,
   234→            lower: prediction - margin,
   235→            upper: prediction + margin,
   236→            level,
   237→        });
   238→    }
   239→    
   240→    Ok(intervals)
   241→}
   242→
   243→/// Simultaneous confidence bands using Working-Hotelling method
   244→///
   245→/// Provides confidence bands that cover the entire regression line
   246→/// with the specified confidence level
   247→pub fn working_hotelling_bands(
   248→    x: &Mat<f64>,
   249→    beta: &[f64],
   250→    cov_beta: &Mat<f64>,
   251→    sigma: f64,
   252→    df: usize,
   253→    level: f64,
   254→) -> Result<Vec<ConfidenceInterval>, String> {
   255→    let n = x.nrows();
   256→    let p = x.ncols();
   257→    
   258→    // Working-Hotelling multiplier: sqrt(p * F_{p,n-p,1-alpha})
   259→    use statrs::distribution::FisherSnedecor;
   260→    let f_dist = FisherSnedecor::new(p as f64, df as f64)
   261→        .map_err(|e| e.to_string())?;
   262→    let f_critical = f_dist.inverse_cdf(level);
   263→    let wh_multiplier = (p as f64 * f_critical).sqrt();
   264→    
   265→    let mut bands = Vec::with_capacity(n);
   266→    
   267→    for i in 0..n {
   268→        // Compute fitted value
   269→        let mut fitted = 0.0;
   270→        for j in 0..p {
   271→            fitted += x[(i, j)] * beta[j];
   272→        }
   273→        
   274→        // Compute standard error of fitted value
   275→        let mut var_fitted = 0.0;
   276→        for j in 0..p {
   277→            for k in 0..p {
   278→                var_fitted += x[(i, j)] * cov_beta[(j, k)] * x[(i, k)];
   279→            }
   280→        }
   281→        let se_fitted = var_fitted.sqrt();
   282→        
   283→        let margin = wh_multiplier * se_fitted;
   284→        
   285→        bands.push(ConfidenceInterval {
   286→            estimate: fitted,
   287→            lower: fitted - margin,
   288→            upper: fitted + margin,
   289→            level,
   290→        });
   291→    }
   292→    
   293→    Ok(bands)
   294→}
   295→
   296→#[cfg(test)]
   297→mod tests {
   298→    use super::*;
   299→    use approx::assert_relative_eq;
   300→    
   301→    #[test]
   302→    fn test_parameter_confidence_intervals() {
   303→        let estimates = vec![1.0, 2.0, 3.0];
   304→        let std_errors = vec![0.1, 0.2, 0.15];
   305→        let df = Some(10);
   306→        let level = 0.95;
   307→        
   308→        let intervals = parameter_confidence_intervals(&estimates, &std_errors, df, level).unwrap();
   309→        
   310→        assert_eq!(intervals.len(), 3);
   311→        
   312→        // Check that estimates are centered in intervals
   313→        for (est, ci) in estimates.iter().zip(&intervals) {
   314→            assert_relative_eq!(*est, ci.estimate, epsilon = 1e-10);
   315→            assert!(ci.lower < *est);
   316→            assert!(ci.upper > *est);
   317→            assert_relative_eq!(ci.level, level, epsilon = 1e-10);
   318→        }
   319→    }
   320→    
   321→    #[test]
   322→    fn test_interval_contains() {
   323→        let ci = ConfidenceInterval {
   324→            estimate: 2.0,
   325→            lower: 1.0,
   326→            upper: 3.0,
   327→            level: 0.95,
   328→        };
   329→        
   330→        assert!(ci.contains(2.0));
   331→        assert!(ci.contains(1.5));
   332→        assert!(!ci.contains(0.5));
   333→        assert!(!ci.contains(3.5));
   334→        
   335→        assert_relative_eq!(ci.width(), 2.0, epsilon = 1e-10);
   336→    }
   337→    
   338→    #[test]
   339→    fn test_linear_combination_ci() {
   340→        let estimates = vec![1.0, 2.0];
   341→        let cov_matrix = Mat::from_fn(2, 2, |i, j| {
   342→            if i == j { 0.1 } else { 0.01 }
   343→        });
   344→        let weights = vec![1.0, -1.0]; // Difference between parameters
   345→        
   346→        let ci = linear_combination_confidence_interval(
   347→            &estimates,
   348→            &cov_matrix,
   349→            &weights,
   350→            Some(10),
   351→            0.95
   352→        ).unwrap();
   353→        
   354→        assert_relative_eq!(ci.estimate, -1.0, epsilon = 1e-10); // 1.0 - 2.0
   355→        assert!(ci.lower < ci.estimate);
   356→        assert!(ci.upper > ci.estimate);
   357→    }
   358→}

